/// Different ways to allocate registers.
enum wasmtime_regalloc_algorithm_enum {
  /// Generates the fastest possible code, but may take longer.
  WASMTIME_REGALLOC_BACKTRACKING(0),

  /// Generates acceptable code very quickly.
  WASMTIME_REGALLOC_SINGLE_PASS(1);

  final int value;
  const wasmtime_regalloc_algorithm_enum(this.value);

  static wasmtime_regalloc_algorithm_enum fromValue(int value) =>
      switch (value) {
        0 => WASMTIME_REGALLOC_BACKTRACKING,
        1 => WASMTIME_REGALLOC_SINGLE_PASS,
        _ => throw ArgumentError(
          'Unknown value for wasmtime_regalloc_algorithm_enum: $value',
        ),
      };
}

